import jwt
from datetime import timedelta

def generate_jwt(user_id, role):
    # Set the JWT signing algorithm to HS256
    algorithm = 'HS256'
    
    # Set the JWT expiration time to 1 hour
    expires = timedelta(hours=1)
    
    # Generate a JWT with the user ID and role
    token = jwt.encode({'user_id': user_id, 'role': role}, algorithm, expires)
    
    return token